import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { XMarkIcon } from "@heroicons/react/24/solid";

export default function EditProfileModal({ closeModal }) {
  const [user, setUser] = useState(null);
  const [name, setName] = useState("");

  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState("");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");

  // LOAD PROFILE
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("user") || "{}");

    if (!stored?.email) {
      closeModal?.();
      return;
    }

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => {
        setUser(res.data);
        setName(res.data.name);
        setPreview(res.data.profileImage);
      })
      .catch(() => {
        Swal.fire("Error", "Failed to load profile", "error");
      });
  }, [closeModal]);

  // IMAGE PREVIEW
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);

    const reader = new FileReader();
    reader.onloadend = () => setPreview(reader.result);
    reader.readAsDataURL(file);
  };

  // UPDATE PROFILE
  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);

      if (imageFile) formData.append("image", imageFile);

      const res = await axios.put(
        "http://localhost:8086/user/update-profile",
        formData
      );

      localStorage.setItem("user", JSON.stringify(res.data));

      Swal.fire("Success", "Profile updated", "success");
      closeModal?.();
    } catch (err) {
      Swal.fire("Error", "Update failed", "error");
    }
  };

  // CHANGE PASSWORD
  const handleChangePassword = async () => {
    try {
      const res = await axios.put(
        "http://localhost:8086/user/change-password",
        {
          email: user.email,
          currentPassword,
          newPassword,
        }
      );

      Swal.fire("Success", res.data.message, "success");

      setCurrentPassword("");
      setNewPassword("");
    } catch (err) {
      Swal.fire(
        "Error",
        err.response?.data?.message || "Password update failed",
        "error"
      );
    }
  };

  if (!user) return null;

  return (
    <div className="fixed inset-0 flex items-center justify-center z-50">

      {/* BACKDROP (no color, only blur) */}
      <div
        className="absolute inset-0 backdrop-blur-sm"
        onClick={closeModal}
      />

      {/* CARD */}
      <div className="relative w-[500px] p-8 rounded-2xl
        backdrop-blur-xl bg-white/20
        border border-white/30 shadow-2xl"
      >
        {/* CLOSE */}
        <button
          onClick={closeModal}
          className="absolute top-3 right-3 text-white hover:text-red-400"
        >
          <XMarkIcon className="w-6 h-6" />
        </button>

        <h2 className="text-2xl font-bold text-center text-white mb-6">
          ✨ Edit Profile
        </h2>

        {/* IMAGE */}
        <div className="flex flex-col items-center mb-6">
          <img
            src={
              preview ||
              user.profileImage ||
              `https://ui-avatars.com/api/?name=${user.username}`
            }
            className="w-28 h-28 rounded-full object-cover border-4 border-white shadow-lg"
          />

          <input
            type="file"
            accept="image/*"
            onChange={handleImageChange}
            className="mt-4 text-sm text-white file:bg-white/30 file:text-white
            file:px-4 file:py-2 file:rounded-full file:border-0"
          />
        </div>

        {/* NAME */}
        <input
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="Full Name"
          className="w-full px-4 py-2 rounded-lg bg-white/20 text-white
          placeholder-white/70 border border-white/30 mb-4"
        />

        {/* SAVE */}
        <button
          onClick={handleUpdateProfile}
          className="w-full py-2 rounded-lg bg-white/30 hover:bg-white/40
          text-white font-semibold"
        >
          Save Changes
        </button>

        <div className="my-6 border-t border-white/30"></div>

        <h3 className="text-white font-semibold mb-3">
          🔒 Change Password
        </h3>

        <input
          type="password"
          placeholder="Current Password"
          value={currentPassword}
          onChange={(e) => setCurrentPassword(e.target.value)}
          className="w-full px-4 py-2 rounded-lg bg-white/20 text-white mb-3"
        />

        <input
          type="password"
          placeholder="New Password"
          value={newPassword}
          onChange={(e) => setNewPassword(e.target.value)}
          className="w-full px-4 py-2 rounded-lg bg-white/20 text-white"
        />

        <button
          onClick={handleChangePassword}
          className="w-full mt-4 py-2 rounded-lg bg-indigo-500/60 hover:bg-indigo-500/80 text-white"
        >
          Update Password
        </button>
      </div>
    </div>
  );
}
